module heater_system (
	input clk,
	input resetn,
	input enable,
	output reg heating);

	parameter OFF=0, HEATING=1;
	reg alt_state, next_state;

	always @(posedge clk) begin
		if (~resetn) alt_state <= OFF;
		else alt_state <= next_state;
	end

	always_comb begin
		case (alt_state)
			OFF: next_state = enable ? HEATING : OFF;
			HEATING: next_state = OFF;
			default: next_state = OFF;
		endcase
	end

	always @(alt_state) begin
		case (alt_state)
			HEATING: heating = 1;
			default: heating = 0;
		endcase
	end
endmodule
